def self_test():
    missing=[p for p in GENERATED if not (ROOT/p).exists()]
    json_errors=[]; py_errors=[]
    for p in GENERATED:
        if p.endswith(".json"):
            try: json.loads((ROOT/p).read_text(encoding="utf-8"))
            except Exception as e: json_errors.append({"path":p,"error":str(e)})
        if p.endswith(".py"):
            try: py_compile.compile(str(ROOT/p),doraise=True)
            except Exception as e: py_errors.append({"path":p,"error":str(e)})
    t=run(["python3","product/api/tests/test_material_admission_matrices.py"])
    res=rjson("outputs/prod8501_8540_material_admission_matrices_method_canonization.json",{})
    cal=res.get("calibration_decision",{})
    checks={"generated_missing_count":len(missing),"json_errors_count":len(json_errors),"py_errors_count":len(py_errors),"static_tests_passed":t.get("ok") is True,"material_taxonomy_matrix_ready":cal.get("material_taxonomy_matrix_ready") is True,"material_dimensional_matrix_ready":cal.get("material_dimensional_matrix_ready") is True,"material_drag_iaso_matrix_ready":cal.get("material_drag_iaso_matrix_ready") is True,"material_granularity_matrix_ready":cal.get("material_granularity_matrix_ready") is True,"material_admission_gate_matrix_ready":cal.get("material_admission_gate_matrix_ready") is True,"domain_material_intersection_matrix_ready":cal.get("domain_material_intersection_matrix_ready") is True,"claim_evidence_action_matrix_ready":cal.get("claim_evidence_action_matrix_ready") is True,"micrograph_runtime_current_poc_false":cal.get("micrograph_runtime_current_poc") is False,"client_claim_allowed_false":cal.get("client_claim_allowed") is False,"production_allowed_false":cal.get("production_allowed") is False}
    passed=not missing and not json_errors and not py_errors and all(v is True or (isinstance(v,int) and v==0) for v in checks.values())
    return {"status":"PASS" if passed else "FAIL","phase":PHASE,"checks":checks,"generated_missing":missing,"json_errors":json_errors,"py_errors":py_errors,"static_test":t}

def commit_plan():
    paths=["apply_prod8501_8540_material_admission_matrices_method_canonization.py"]+GENERATED
    lines=["git add \\"]
    lines += [f"  {p} \\" for p in paths[:-1]]
    lines.append(f"  {paths[-1]}")
    lines += ["",'git commit -m "Add material admission matrices and methodology canonization start"','git tag -a product-casulo-material-admission-matrices-v0.1 HEAD -m "CASULO material admission matrices v0.1"',"git push origin main","git push origin product-casulo-material-admission-matrices-v0.1"]
    return "\n".join(lines)

def main():
    ap=argparse.ArgumentParser(); ap.add_argument("--check",action="store_true"); ap.add_argument("--apply",action="store_true"); ap.add_argument("--self-test",action="store_true"); ap.add_argument("--commit-plan",action="store_true")
    args=ap.parse_args()
    if not any(vars(args).values()): args.check=True
    if args.check: print(json.dumps(check(),indent=2,ensure_ascii=False))
    if args.apply:
        c=check()
        if c["status"]!="PASS":
            print(json.dumps(c,indent=2,ensure_ascii=False)); raise SystemExit("CHECK_FAILED")
        wrote=apply(); print(json.dumps({"applied":True,"wrote_count":len(wrote),"wrote":wrote},indent=2,ensure_ascii=False))
    if args.self_test: print(json.dumps(self_test(),indent=2,ensure_ascii=False))
    if args.commit_plan: print(commit_plan())
if __name__=="__main__": main()
